import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { adminDashboardDesign } from "../../design/adminDashboardDesign";

const AdminDashboard = () => {
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));
  const [isOpen, setIsOpen] = useState(true);

  return (
    <div className={adminDashboardDesign.layout.wrapper}>

      {/* 🔥 Sidebar */}
      <AnimatePresence>
        {isOpen && (
          <motion.aside
            {...adminDashboardDesign.animation.sidebar}
            className={`${adminDashboardDesign.colors.sidebar} ${adminDashboardDesign.layout.sidebarBase}`}
          >
            <h2 className="text-2xl font-bold text-indigo-400">
              Admin Panel
            </h2>

            <nav className="space-y-3">
              <div className={`${adminDashboardDesign.layout.navItem} ${adminDashboardDesign.colors.hover}`}>
                Dashboard
              </div>
              <div className={`${adminDashboardDesign.layout.navItem} ${adminDashboardDesign.colors.hover}`}>
                Products
              </div>
              <div className={`${adminDashboardDesign.layout.navItem} ${adminDashboardDesign.colors.hover}`}>
                Orders
              </div>
              <div className={`${adminDashboardDesign.layout.navItem} ${adminDashboardDesign.colors.hover}`}>
                Users
              </div>
            </nav>
          </motion.aside>
        )}
      </AnimatePresence>

      {/* 🔥 Right Side */}
      <div
        className={`${adminDashboardDesign.layout.contentWrapper} ${
          isOpen ? adminDashboardDesign.layout.contentShift : ""
        }`}
      >
        {/* Navbar */}
        <div className={`${adminDashboardDesign.colors.navbar} ${adminDashboardDesign.layout.navbar}`}>
          
          {/* Toggle Button */}
          <button
            onClick={() => setIsOpen(!isOpen)}
            className={adminDashboardDesign.colors.toggleBtn}
          >
            ☰
          </button>

          <div className="flex items-center gap-4">
            <span className="text-sm text-gray-600">
              {adminInfo?.name}
            </span>
            <div className="w-8 h-8 bg-indigo-500 rounded-full"></div>
          </div>
        </div>

        {/* Main Content */}
        <motion.div
          {...adminDashboardDesign.animation.contentFade}
          className={adminDashboardDesign.layout.content}
        >
          <h2 className="text-2xl font-bold mb-4">
            Welcome Back 👋
          </h2>

          <p className="text-gray-600">
            This is your admin dashboard overview.
          </p>
        </motion.div>
      </div>
    </div>
  );
};

export default AdminDashboard;
